// Code Tool: extract structured lead data from the agent's query
// Fields: name, email, query, appointment, status, buyer type
// Input: `query` (string) — either a JSON string or free/labeled text
// Output: a single JSON string the agent can read back

function extractField(text, labels) {
  for (const label of labels) {
    const regex = new RegExp(label + "\\s*[:\\-]\\s*([^\\n,;]+)", "i");
    const match = text.match(regex);
    if (match) return match[1].trim();
  }
  return null;
}

let result;

// Case 1: agent already sent structured JSON
try {
  const parsed = JSON.parse(query);
  result = {
    name: parsed.name ?? null,
    email: parsed.email ?? null,
    query: parsed.query ?? null,
    appointment: parsed.appointment ?? null,
    status: parsed.status ?? null,
    buyer_type: parsed.buyer_type ?? parsed.buyerType ?? null,
  };
} catch (e) {
  // Case 2: fall back to parsing free/labeled text
  const text = query;

  const emailMatch = text.match(/[\w.+-]+@[\w-]+\.[\w.-]+/);

  result = {
    name: extractField(text, ["name"]),
    email: emailMatch ? emailMatch[0] : extractField(text, ["email"]),
    query: extractField(text, ["query", "message", "inquiry"]),
    appointment: extractField(text, ["appointment", "appt", "date", "meeting"]),
    status: extractField(text, ["status"]),
    buyer_type: extractField(text, ["buyer type", "buyer", "type"]),
  };
}

// Basic validation flags — helps the agent know what's still missing
result.missing_fields = Object.entries(result)
  .filter(([key, val]) => key !== "missing_fields" && !val)
  .map(([key]) => key);

return JSON.stringify(result);
